class Solution:
    def solve(self, nums, k):
        if k > len(nums):
            return
        nums = nums[:k-1] + nums[k:]
        for i in range(len(nums) // 2 - 1, -1, -1):
            self.heapify(nums, i, len(nums) - 1)

    def heapify(self, nums, n, m):
        if m <= n:
            return
        max_index = m
        left_child = n * 2 + 1
        right_child = n * 2 + 2
        if left_child <= m and nums[left_child] > nums[max_index]:
            max_index = left_child
        if right_child <= m and nums[right_child] > nums[max_index]:
            max_index = right_child
        if max_index != m:
            nums[n], nums[max_index] = nums[max_index], nums[n]
            self.heapify(nums, max_index, m)

